INSERT INTO bl_line_items (bl_id, product_id, quantity, capacity_kw, item_type, payment_type, usage_category)
SELECT nl.bl_id, nl.product_id, nl.quantity, nl.capacity_kw, 'main', 'paid', 'sale'
FROM new_lines nl
WHERE NOT EXISTS (SELECT 1 FROM bl_line_items WHERE bl_id = nl.bl_id AND product_id = nl.product_id);

-- 검증
SELECT 'after' AS stage, COUNT(*) AS lines, COUNT(DISTINCT bl_id) AS bls
  FROM bl_line_items;

COMMIT;